const Q_IRK_2019_MODEL=[{"id": "objective>IRK>2019 Model>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the hadīth that ends with '...piety is based right here ...', the Prophet (S.A.W.) meant the  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart </div>", "<div style=\"font-family:Cambria;font-size:17px;\">City of Makkah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">City of al-Madīnah </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Piety is here\" - and he pointed to his chest three times. \"It is enough of evil for a person to hold his brother Muslim in contempt. As a muslims our exterior beauty, skin colour, clothes should not be our major concern but also what his in our heart, we should try and clean our heart of evil thoughts.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2019 Model>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Asmā' ar - rijāl is a term used by scholars of  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> jurisprudence </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Hadīth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Usūl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">History </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">`Ilm al- Rijāl ; literally meaning 'Knowledge of Men' , but more commonly understood as the Science of Narrators) refers to a discipline of Islamic religious studies within hadith terminology in which the narrators of hadith are evaluated. <br/> </div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2019 Model>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'It is most hateful in the sight of Allah that you say that which you do not' (Q. 61:3). The main teaching of the verse above is honesty in  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Words</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Words and deeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deeds and worship </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">: It was reported that some of them said 'I fought while he did not, and I attacked while he did not' and 'I did such and such' but he did not. So Allah (swt) revealed this verse reprimanding them in general without specifying the matter for which they were reprimanded. Therefore, the reprimand is for anyone who says something but does not do it. <br/> 'It is deeply abhorrent to Allah that you should say what you do not do.' <br/> </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : HONESTY"}, {"id": "objective>IRK>2019 Model>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the above, the goal of luqmān's counsel to his son:... As contained in sūrah 31:13 is to  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Discourage pride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encourage goodness to parents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warn against finding partners for Allah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uphold the principle of justice </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">O my son! Join not in worship others with Allah. <br/> Allah tells us how Luqman advised his son. His full name was Luqman bin `Anqa' bin Sadun, and his son's name was Tharan, according to a saying quoted by As-Suhayli. <br/> Allah describes him in the best terms, and states that he granted him wisdom. Luqman advised his son, the closest and most beloved of all people to him, who deserved to be given the best of his knowledge. So, Luqman started by advising him to worship Allah Alone, and not to associate  anything with Him. Read Surah 31:13 for full text. <br/> </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : GENERAL MORAL LESSONS CONTAINED IN THE ADMONITION OF SAGE LUQMAN TO HIS SON"}, {"id": "objective>IRK>2019 Model>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ihyā' 'Ulūm ad-dīn is the title of a book written by  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ibn Sīna </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> al-Ghazālī </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ar-Rāzī </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ibn Rushd</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">al - Ghazali . Al -Ghazâlî (c. 1056-1111) was one of the most prominent and influential philosophers, theologians, jurists, and mystics of Sunni Islam. He wrote ūlūm ad-din. <br/> </div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE LIVES AND CONTRIBUTIONS OF IBN SINA, AL-GHAZALI, IBN RUSHDI, AR-RAZIO AND IBN KHALDUN TO EDUCATION."}, {"id": "objective>IRK>2019 Model>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways by which Islamic civilization was manifested in West Africa was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the employment of scholars of Arabic as envoys by kings and emperors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction of palaces based on Arab technology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of universities to train scientists </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recruitment of Muslim medical personnel to man health institutions </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Islamic civilization was manifested through employment of Scholars, of Arab as envoys by the king's Islam.</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}, {"id": "objective>IRK>2019 Model>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ahmad bab, one of the early West African 'Ulamā', was based in  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sokoto</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Borno </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Timbuktu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Timbuktu is a city in Mali, situated 20 km north of the Niger River. The town is the capital of the Timbuktu Region, one of the eight administrative regions of Mali. It had a population of 54,453 in the 2009 census <br/> </div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : INTELLECTUAL ACTIVITIES OF AHMAD BABA OF TIMBUKTU, SHEIKHAL-MAGHILI, SHEIKH USMAN DANFODIO, SULTAN MUHAMMAD BELLO AND IBN BATTUTA"}, {"id": "objective>IRK>2019 Model>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ignorance of religious rites and duties is not excusable in Islam because  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is obligatory on all Muslims to seek knowledge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">most Muslims can read and write Arabic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">books of Islamic jurisprudence have been translated into many languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Islamic system of education is highly developed all over the world <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ignorance is the absence of common sense and basic knowledge. Ignorance is the attribute of the arrogant, egoistic and selfish people. When people indulge in self importance only and are being arrogant, being egoistic, being selfish and just care about worldly status are good example of ignorant people. These attributes make them deaf, dumb and blind so they can not differentiate between true and false, good and bad, right and wrong and just follow whims and desires blindly.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2019 Model>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'Still less can their knowledge comprehend the hereafter ...' Q. 27:66).This verse above of the Qur'ān implies that  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">man's knowledge of the Hereafter can only be partial </div>", "<div style=\"font-family:Cambria;font-size:17px;\">most men do not believe in the Hereafter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">man's comprehension of the expectations in the Hereafter is a always on the decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is difficult to deceive in the Hereafter </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(27:66) Nay, but they have lost their knowledge of the Hereafter. They are steeped in doubt and uncertainty about it: rather they are blind to it.  After warning the people about their basic errors with regard to Divinity, it is being said that the reason why these people are involved in these errors is not that they have reached this conclusion after serious thought and deliberation that there also exist other beings who are Allah's associates in His Divinity, but the actual reason is that they have never considered this matter seriously. As they are unaware of the Hereafter, or are in doubt about it, or are blind to it, their heedlessness of the Hereafter has developed in them an utterly irresponsible attitude. They are not at all serious about the universe and the real problems of their own lives. They do not bother to know what reality is and whether their philosophy of life accords with that reality or not. For, according to them, in the end the polytheist and the atheist, the monotheist and the agnostic, all will become one with the dust after death, and nothing will bear any fruit. <br/> The theme of the Hereafter is contained in this sentence of the preceding verse: \"They do not know when they will be raised back to life.\" In that sentence it was said that those who are made deities, the angels, jinns, prophets, saints, etc., do not themselves know when will be the Resurrection. Here three things have been said about the common polytheists and the atheists: (1) They do not at all know whether there will be any Hereafter or not; (2) this lack of information on their part is not due to the reason that they were never informed of this, but because they did not believe in the information given to them and doubted its authenticity; and (3) they never bothered to consider with due thought and seriousness the arguments that were advanced about the coming of the Hereafter, but they preferred to remain blind to it. <br/> </div>", "topic": "ARTICLE OF FAITH : THE LAST DAY: YAWM-AL-BA'TH"}, {"id": "objective>IRK>2019 Model>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Islamic teachings, angels are  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">like human beings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">of divine nature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a class of jinns </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> loyal servants of Allah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">: Angels are believed to be celestial beings, created from a luminous origin by God . They have different functions, including praising God in heavens, interacting with humans ordinary life, and carrying laws of nature. Islam acknowledges the concept of angels both as anthropomorphic and abstract. Belief in angels is one of the six <br/> articles of faith in Islam. The Quran is the principal source for the Islamic concept of angels, but more extensive features of angels appear in hadiths , Mi'raj literature, Islamic theology and Islamic philosophy .  The angels differ from other spiritual creatures in their attitude as creatures of virtue in contrast to impure demons and morally ambivalent jinn . <br/> </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH'S ANGELS"}, {"id": "objective>IRK>2019 Model>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prophet whose wife was impious and consequently suffered the same calamity with the unbelievers was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shu'aib</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yūsuf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mūsa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lūt</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet let was sent to Sodom and Gomorrah to preach to the people to turn away from their sexual immorality (men were sleeping with men, women were sleeping with women), the people of Sodom and Gomorrah, refused to listen to lūt warning. They even assaulted him, then Allah sent an angel to tell lot to leave with his family away from there because Allah wants to destroy the city. <br/> Allah had decreed that the city of Sodom should perish. An earthquake rocked the town. It was as if a mighty power had lifted the entire city and flung it down in one jolt. A storm of stones rained on the city. Everyone and everything was destroyed, including Lūt's wife. <br/> </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2019 Model>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aspect of the Nigerian culture which may be regarded as shirk is  <br/> between boys and girls</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excessive spending at burial ceremonies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">worship of ancestors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">signing and dancing in public </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ceremonies involving social interaction between boys and girls <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shirk means  \"making a partner [of someone]\" in Islam , idolatry, polytheism, and the association of God with other deities. It is a sin to serve any idol before Almighty Allah, before Allah is the only powerful and most Holy.</div>", "topic": "TAWHID AND FIQH : SHIRK"}, {"id": "objective>IRK>2019 Model>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Qur'ān 4:48, to set up partners with Allah is a great offense which Allah will not forgive  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">except the Prophet (S.A.W) intercedes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">until He has forgiven all other sins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">except the offender repents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">even if He forgives all other sins. </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qu'ran 4:48 \"Surely Allah does not forgive that a partner be ascribed to Him, although He forgives any other sins for whomever He wills. He who associates anyone with Allah in His divinity has indeed forged a mighty lie and committed an awesome sin.\"  It is a great sin if one create or ascribe any other good or partner to Allah. Allah forgives all sins, but he won't forgive this. <br/> </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2019 Model>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The man who analyzed the first encounter the Prophet (S.A.W) with Angel Jibril was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hatīb b. Abī Balta'a </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waraqah b. Nawfal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arqam b. Arqam </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 'Uthmān b. 'Affān</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Waraqah ibn Nawfal. Warqah ibn Nawfal ibn Asad ibn Abd-al-Uzza ibn Qusayy Al-Qurashi (Arabic ﻭﺭﻗﻪ ﺑﻦ ﻧﻮﻓﻞ ﺑﻦ ﺃﺳﺪ ﺑﻦ ﻋﺒﺪ ﺍﻟﻌﺰّﻯ ﺑﻦ ﻗﺼﻲ ﺍﻟﻘﺮﺷﻲ ) was an Arab priest and the paternal first cousin of Khadija bint Khuwaylid, the first wife of the Islamic prophet Muhammad. <br/> </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS CALL TO PROPHETHOOD"}, {"id": "objective>IRK>2019 Model>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above, is an expression of man's absolute  <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loyalty to 'Allāℎ </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dependence on 'Allāℎ </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obedience to 'Allāℎ </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> humility to 'Allāℎ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse speaks about man loyalty to Almighty Allah, and man we forever praise, worship, pray and and preach his glory. <br/> </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2019 Model>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In sūrah al-Qāri'ah, mankind is compared to  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scattered moths </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laden camels </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pampered creatures </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> humiliated beasts.  <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah 101 Al Qari'ah  \"The day of Noise and Clamour:  <br/> What is the Day  of Noise and Clamour? <br/> And what will explain to thee, what the  Day of Noise and Clamour is? <br/> It is a Day whereon men will be like moths scattered about,  <br/> And the mountains will like carded wool.  <br/> Then, he whose balance of good deeds will be found heavy, <br/> Will be in a Life of good pleasure and satisfaction. <br/> But he whose balance of  good deeds will be found light - Will have his home in a bottomless Pit. <br/> And what will explain to thee what this is? It is a Fire blazing fiercely!\" <br/> </div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -QARI'AH"}, {"id": "objective>IRK>2019 Model>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fount (of abundance) was given to the Prophet (S.A.W) and made known to him in sūrah  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Mā' ūn </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Takāthur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an-Nasr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al-Kawthar</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah Al-kawthar  \"Do you know what Al-Kawthar is?\" They replied, \"Allah and His Messenger know best.\" He said: \"It is a river granted to me by my Lord, the Almighty, the All-Powerful in Paradise, in which is great goodness; its drinking vessels are as (limitless as) the heavenly bodies. It refuses to allow one of the slaves to drink, and the Prophet will say: 'Oh, my Lord! He is one of my community.' But it will be said to him: 'You know nothing of the innovations (in religion) that they practiced after you.\" You can check the Holy Qu'ran to read the full verse. <br/> </div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2019 Model>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Who among the four rightly guided caliphs introduced the systems of Bayr at māl?  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abū Bakr as Siddīq </div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Umar b. al-Khattāb </div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Uthmān b. 'Affān </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 'Ali b. ' Abī Tālib.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bayt al-mal ( ﺑﻴﺖ ﺍﻟﻤﺎﻝ ) is an Arabic term that is translated as \"House of money\" or \"House of Wealth.\" Historically, it was a financial institution responsible for the administration of taxes in Islamic states , particularly in the early Islamic Caliphate . It served as a royal treasury for the caliphs and sultans , managing personal finances and government expenditures. Further, it administered distributions of zakat revenues for public works.  <br/> </div>", "topic": "THE RIGHTLY GUIDED CALIPHS AL-KHULAFA'U RASHIDUN : THE LIVES AND CONTRIBUTIONS OF THE FOUR RIGHTLY GUIDED CALIPHS"}, {"id": "objective>IRK>2019 Model>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Muslim soldier who introduced Islam into Tripoli was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">'Uqbah b. Nāfī </div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Uqbah b. Sacad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sa'ād b. Abi Waqās </div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Amar b. al ās </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ʿUqba ibn Nāfiʿ ( Arabic : ﻋﻘﺒﺔ ﺑﻦ ﻧﺎﻓﻊ ), also referred to as Oqba ibn Nafi, Uqba bin Nafe, Uqba ibn al Nafia, or Akbah; 622-683) was an Arab general serving the Rashidun Caliphate since the Reign of Umar and later on the Umayyad Caliphate during the reigns of Muawiyah I and Yazid I , leading the Muslim conquest of the Maghreb , including present-day Algeria, Tunisia , Libya(Tripoli Is the capital of Libya) andMorocco . <br/> </div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE SPREAD OF ISLAM TO EGYPT"}, {"id": "objective>IRK>2019 Model>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors which helped the spread of Islam in West Africa was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the building of a mosque in Timbuktu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the establishment of many schools </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective trade relationship </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of clans and kingdoms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The introduction of Islam to West Africa, wasn't violence or forced, it was done in an orderly and peaceful manner, through making friends with them, entering into trading business with them. Through that, they were able to gain there trust and Islam was introduced and taught to them. <br/> </div>", "topic": "THE IMPACT OF ISLAM IN WEST AFRICA : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}, {"id": "objective>IRK>2019 Model>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first man on earth, Adam (A.S), was exalted above other creatures because of his  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Intelligence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obedience </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Insight </div>", "<div style=\"font-family:Cambria;font-size:17px;\">knowledge</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">when Allah created man, he created him in his own image, and he gave him more knowledge and authority over all the other creatures. He gave made man the custodian of other creatures created by him.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2019 Model>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Who among the prophets of 'Allāh was sent to his people to warn against deceit in term of measurement and weight  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shuaib (A.S.) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hud (A.S) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Salih (A.S) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuh (A.S) </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chiefs of those who disbelieved among his people said to their people: \"If you follow Shu'aib be sure then you will be the losers!\" <br/> Then he (shu'aib) turned from them and said: \"O my people! I have indeed conveyed my Lord's Messages unto you and I have given you good advice. Then how can I sorrow for the disbelieving people's (destruction).\" (7:85-93 Quran) <br/> </div>", "topic": "ARTICLE OF FAITH : HIS PROPHETS: ULUL-AZMI"}, {"id": "objective>IRK>2019 Model>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The worst vice prevalent during the Jahiliyyah period was  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Disloyalty</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Insincerity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cowardice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vengeance. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jāhiliyyah, in Islam, the period preceding the revelation of the Qurʾān to the Prophet Muhammad. In Arabic the word means \"ignorance,\" or \"barbarism,\" and indicates a negative Muslim evaluation of pre-Islamic life and culture in Arabia as compared to the teachings and practices of Islam. <br/> </div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2019 Model>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Jahiliyyah practice that was gradually phased out is  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gambling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adultery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Usury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alcoholism. </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abolishing Alcoholism is one of the reform that was introduced during  Jāhiliyyah. It was made known that Allah frowns at alcoholism and we Muslims must not take alcohol, because it is a sin. <br/> </div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : ISLAMIC REFORMS"}, {"id": "objective>IRK>2019 Model>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the most outstanding developments after the Hijrah was the  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emergence of a new religion </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> increase in hostilities against the Muslims </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergence of the Muslim </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> increase in cooperation with the Jews  <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hegira is the migration or journey of the Islamic prophet Muhammad and his followers from Mecca to Yathrib, later renamed by him Medina, in the year 622. <br/> Muslims ummah is a theory that no matter where you come from, as long as you are a Muslim, you are a member of a worldwide family. <br/> Prophet Muhammud migration (Hegira) brought about this development. <br/> </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE HIJRAH"}, {"id": "objective>IRK>2019 Model>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Makkan forces were not successful at the battle of Khandaq because they  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> were afraid of another defeat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ran out of supplies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">were not properly coordinated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">were not familiar with the strategy of the Muslims </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The battle of khandaq was a battle of wits, the Muslims were out numbered but they used a defensive strategy of digging a trench(khandaq) which was used to trap most of the Arab. The siege was a \"battle of wits\", in which the Muslims tactically overcame their opponents while suffering very few casualties. Efforts to defeat the Muslims failed, and Islam became influential in the region. As a consequence, the Muslim army besieged the area of the Banu Qurayza tribe , leading to their surrender. <br/> The defeat caused the Meccans to lose their trade and much of their prestige. <br/> </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>2019 Model>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of knowledge of isnād and matn lies in the fact that  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both were taught by the Prophet (S.A.W) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the two make it easy to memorize Hadītℎ </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the two make it easy to identify fault in Hadīth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they make it possible to understand Hadīth.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">it is also called  science of hadith, or <br/> science of hadith criticism or hadith criticism. It consists of several religious scholarly disciplines used in the study and evaluation of the Islamic hadith - i.e. the record of the words, actions, and the silent approval of the Islamic prophet, Muhammad, by Muslim scholars. Determining authenticity of hadith is enormously important in Islam because along with the Quran , the Sunnah of the Islamic prophet-his words, actions, and the silent approval-are considered divine revelation ( wahy ), and the record of them (i.e. hadith) provides the basis of Islamic law ( Sharia ).  <br/> </div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2019 Model>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term al-Mutawātir refers to Hadīth narrated by  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bukhari and Muslim </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the six sound collectors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Prophet's closest companions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large number of narrators</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al- Mutawatir is an Arabic word uptake which means \"to be lowered from person to person\". This term is used in the study of Ulum al-Quran and Mustalah Hadith. According to the hadith scholars, the above hadith is narrated by more than one hundred Prophet's companions with a hundred different sanad. <br/> </div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2019 Model>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W) enjoins that if anyone sees an abomination, the least thing to do is to  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">change it with his hands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">condemn it in public </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hate it in his heart </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> turn his eyes away </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Muhammud enjoins Muslims that when they see an abomination, they should avoid and run away from it, even the least they could do is to hate it in their heart. <br/> </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : ENJOINING WHAT IS GOOD AND FORBIDDING WHAT IS WRONG HADITH 25 AND 34 OF AN NAWAWI"}, {"id": "objective>IRK>2019 Model>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Hadīth 31 of an-Nawawi, man will be loved by 'Allāℎ if he is  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Indifferent to the world </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steadfast in prayers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obedient to the prophets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kind to his neighbours </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 31- \"Detach yourself from the world and Allah will love you. Detach yourself from what people possess and they will love you.\"  The message in this Hadith is that if we can stay away from the worldly things, like Drinking alcohol, idolatry, fornication, e.t.c Allah will love you more. <br/> </div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2019 Model>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The statement in Hadīth 25 above gave rise to the explanation as to the different ways by which  <br/>  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prayers can be offered </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alms can be given </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fasting can be observed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pilgrimage can be performed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">this Hadith, brought about giving of charity \"Has not Allah made things for you to give in charity? Truly every tasbeehah [saying: 'subhanAllah'] is a charity, and every takbeerah [saying: 'Allahu akbar'] is a charity, and every tahmeedah [saying: 'al-hamdu lillah'] is a charity, and every tahleelah [saying: 'laa ilaha illaAllah'] is a charity. And commanding the good is a charity, and forbidding an evil is a charity, and in the bud`i [sexual act] of each one of you there is a charity.\" </div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2019 Model>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where the husband and wife mutually agree to termite their marriage contract without anything against each other, such a dissolution is termed  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ilā' </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Faskh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Khul</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mubāra'ah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mubāra'ah. A type of divorce under Islamic law whereby the parties mutually agree to dissolve their marriage. The husband and wife will have a mutual agreement on a good term that they want to end it. <br/> </div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2019 Model>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The period of custody of a baby girl after her mother has been divorced lasts until she is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Married </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10years old </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5years old.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">when a woman is divorced and she has a baby girl, she only has the custody of the girl till she is married. After the girl get married, the woman has no custody over her. <br/> </div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2019 Model>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Islamic law of inheritance, the share of the mother of the deceased who has no children is  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />639</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the Islamic law of inheritance, the share of the mother of the deceased who has no children is 1/3. When a person dies, and he/she has no child, the mother of the deceased is able to take 1/3 of the deceased property. <br/> </div>", "topic": "FAMILY MATTERS : INHERITANCE"}, {"id": "objective>IRK>2019 Model>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fard and Harām in the scope of sharī'ah mean  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tolerable and abominable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">permissible and punishable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compulsory and disliked </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obligatory and prohibited </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">fard \" means \"obligation\". ... For example, fard prayer, wajib prayer, sunnah mu'akkadah prayer, sunnah ghayr-mu'akkadah prayer, nafl prayer, harām prayer, or makrūh tahrēman prayer  <br/> </div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2019 Model>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">'If ye do it not, take notice of war from 'Allah and His Apostle: But if ye turn back,ye shall have your capital sums ...' (Q.2:279) The quotation above warns against  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Usury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gambling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quaran 2:279 \"But if you fail to do so, then be warned of war from Allah and His Messenger.  If you repent even now, you have the right of the return of your capital; neither will you do wrong nor will you be wronged\" <br/> </div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC ATTITUDE TO RIBA HADITH 6TH OF AN-NAWAWI"}, {"id": "objective>IRK>2019 Model>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zakatul-fitr is not permissible on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Millet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kolanut</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zakat al-Fitr is a charity taken for the poor a few days before the end of fasting in the Islamic holy month of Ramadan. One cannot use kolanut as Zakat al-Fitr. <br/> </div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>2019 Model>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Jihād against carnal self is a  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minor jihād </div>", "<div style=\"font-family:Cambria;font-size:17px;\">major jihād </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> compulsory jihād </div>", "<div style=\"font-family:Cambria;font-size:17px;\">desirable jihād </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase internal Jihad or greater Jihad refers to the efforts of a believer to live their Muslim faith as well as possible. All religious people want to live their lives in the way that will please their God. Major jihad is a struggle between oneself to live a holy life. <br/> </div>", "topic": "IBADAT AND THEIR TYPES : JIHAD"}, {"id": "objective>IRK>2019 Model>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Marriage is referred to in Q. 4:21 as  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mirhāq </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nikāh</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ijbar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">khitbah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mirhāq \"And how could you take it [back] while you have gone in unto each other, they have taken from you a firm and strong covenant (Mithaq) Q. 4:21 <br/> </div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2019 Model>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q.4:34 enjoins the wife not only to be obedient but also to  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintain her chastity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect her home </div>", "<div style=\"font-family:Cambria;font-size:17px;\">defend her rights </div>", "<div style=\"font-family:Cambria;font-size:17px;\">endure all difficulties </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Men look after women, because Allah has made the one of them to excel the other, and because they spend of their property (for the support of women). So good women are the obedient, guarding in secret that which Allah hath guarded. As for those from whom ye fear rebellion, admonish them and banish them to beds apart, and scourge them . Then if they obey you, seek not a way against them. Lo! Allah is ever High, Exalted, Great. <br/> </div>", "topic": "FAMILY MATTERS : MARRIAGE"}];
